export function createFigureMask(grayObj,config){const mask=new Uint8Array(grayObj.width*grayObj.height);for(let i=0;i<mask.length;i++){const aOk=!config.useAlpha||grayObj.alpha[i]>config.alphaThreshold;const wOk=!config.removeWhite||grayObj.gray[i]<config.whiteThreshold;mask[i]=(aOk&&wOk)?1:0}return cleanMask(mask,grayObj.width,grayObj.height,config)}
export function cleanMask(mask,w,h,config={}){let out=mask;if(config.closeSmallHoles){out=dilate(out,w,h);out=erode(out,w,h)}if(config.smoothMask){out=erode(dilate(out,w,h),w,h)}if(config.minRegionArea>1)out=removeTinyIslands(out,w,h,config.minRegionArea);return out}
function neigh(mask,w,h,x,y){let c=0;for(let yy=-1;yy<=1;yy++)for(let xx=-1;xx<=1;xx++){const nx=x+xx,ny=y+yy;if(nx>=0&&ny>=0&&nx<w&&ny<h&&mask[ny*w+nx])c++}return c}
export function dilate(m,w,h){const o=new Uint8Array(m.length);for(let y=0;y<h;y++)for(let x=0;x<w;x++)o[y*w+x]=neigh(m,w,h,x,y)>0?1:0;return o}
export function erode(m,w,h){const o=new Uint8Array(m.length);for(let y=0;y<h;y++)for(let x=0;x<w;x++)o[y*w+x]=neigh(m,w,h,x,y)>=5?1:0;return o}
export function removeTinyIslands(m,w,h,min){const o=new Uint8Array(m),seen=new Uint8Array(m.length),q=[];for(let i=0;i<m.length;i++)if(o[i]&&!seen[i]){q.length=0;q.push(i);seen[i]=1;for(let p=0;p<q.length;p++){const id=q[p],x=id%w,y=Math.floor(id/w);[[1,0],[-1,0],[0,1],[0,-1]].forEach(([dx,dy])=>{const nx=x+dx,ny=y+dy,n=ny*w+nx;if(nx>=0&&ny>=0&&nx<w&&ny<h&&o[n]&&!seen[n]){seen[n]=1;q.push(n)}})}if(q.length<min)q.forEach(id=>o[id]=0)}return o}
